import{c as a}from"./chunks/constants.C5IkT81P.js";import{o as e,c as s,aw as o,j as n,t,k as l,a as i}from"./chunks/framework.Dq2onT5h.js";const r={class:"vp-code-group"},p={class:"blocks"},c={class:"language-sh active"},d={class:"shiki ev-dark vp-code",tabindex:"0"},h={class:"line"},u={style:{color:"#BFF3C2"}},F={class:"line"},y={style:{color:"#BFF3C2"}},g={class:"language-sh"},C={class:"shiki ev-dark vp-code",tabindex:"0"},b={class:"line"},v={style:{color:"#BFF3C2"}},f={class:"line"},B={style:{color:"#BFF3C2"}},E={class:"language-sh"},m={class:"shiki ev-dark vp-code",tabindex:"0"},_={class:"line"},A={style:{color:"#BFF3C2"}},k={class:"line"},T={style:{color:"#BFF3C2"}},D=JSON.parse('{"title":"Using Celestia as DA","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Using Celestia as DA | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/da/celestia-da.md","filePath":"guides/da/celestia-da.md","lastUpdated":1759477783000}'),w={name:"guides/da/celestia-da.md"},N=Object.assign(w,{setup:D=>(D,w)=>(e(),s("div",null,[w[25]||(w[25]=o('<h1 id="using-celestia-as-da" tabindex="-1">Using Celestia as DA <a class="header-anchor" href="#using-celestia-as-da" aria-label="Permalink to &quot;Using Celestia as DA&quot;">​</a></h1><h2 id="introduction" tabindex="-1">🌞 Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;🌞 Introduction {#introduction}&quot;">​</a></h2><p>This tutorial serves as a comprehensive guide for deploying your chain on Celestia&#39;s data availability (DA) network. From the Evolve perspective, there&#39;s no difference in posting blocks to Celestia&#39;s testnets or Mainnet Beta.</p><p>Before proceeding, ensure that you have completed the <a href="./../gm-world">gm-world</a> tutorial, which covers installing the Testapp CLI and running a chain against a local DA network.</p><h2 id="🪶-running-a-celestia-light-node" tabindex="-1">🪶 Running a Celestia light node <a class="header-anchor" href="#🪶-running-a-celestia-light-node" aria-label="Permalink to &quot;🪶 Running a Celestia light node&quot;">​</a></h2><p>Before you can start your chain node, you need to initiate, sync, and fund a light node on one of Celestia&#39;s networks on a compatible version:</p><p>Find more information on how to run a light node in the <a href="https://celestia.org/run-a-light-node/#start-up-a-node" target="_blank" rel="noreferrer">Celestia documentation</a>.</p>',7)),n("div",r,[w[24]||(w[24]=o('<div class="tabs"><input type="radio" name="group-gwZgh" id="tab-DvPz-Em" checked><label data-title="Arabica" for="tab-DvPz-Em">Arabica</label><input type="radio" name="group-gwZgh" id="tab-4VoPvkA"><label data-title="Mocha" for="tab-4VoPvkA">Mocha</label><input type="radio" name="group-gwZgh" id="tab-3DC6WCQ"><label data-title="Mainnet" for="tab-3DC6WCQ">Mainnet</label></div>',1)),n("div",p,[n("div",c,[w[6]||(w[6]=n("button",{title:"Copy Code",class:"copy"},null,-1)),w[7]||(w[7]=n("span",{class:"lang"},"sh",-1)),n("pre",d,[n("code",null,[n("span",h,[w[0]||(w[0]=n("span",{style:{color:"#94EEFF"}},"Evolve",-1)),w[1]||(w[1]=n("span",{style:{color:"#BFF3C2"}}," Version:",-1)),n("span",u," "+t(l(a).celestiaNodeArabicaEvolveTag),1)]),w[5]||(w[5]=i("\n",-1)),n("span",F,[w[2]||(w[2]=n("span",{style:{color:"#94EEFF"}},"Celestia",-1)),w[3]||(w[3]=n("span",{style:{color:"#BFF3C2"}}," Node",-1)),w[4]||(w[4]=n("span",{style:{color:"#BFF3C2"}}," Version:",-1)),n("span",y," "+t(l(a).celestiaNodeArabicaTag),1)])])])]),n("div",g,[w[14]||(w[14]=n("button",{title:"Copy Code",class:"copy"},null,-1)),w[15]||(w[15]=n("span",{class:"lang"},"sh",-1)),n("pre",C,[n("code",null,[n("span",b,[w[8]||(w[8]=n("span",{style:{color:"#94EEFF"}},"Evolve",-1)),w[9]||(w[9]=n("span",{style:{color:"#BFF3C2"}}," Version:",-1)),n("span",v," "+t(l(a).celestiaNodeMochaEvolveTag),1)]),w[13]||(w[13]=i("\n",-1)),n("span",f,[w[10]||(w[10]=n("span",{style:{color:"#94EEFF"}},"Celestia",-1)),w[11]||(w[11]=n("span",{style:{color:"#BFF3C2"}}," Node",-1)),w[12]||(w[12]=n("span",{style:{color:"#BFF3C2"}}," Version:",-1)),n("span",B," "+t(l(a).celestiaNodeMochaTag),1)])])])]),n("div",E,[w[22]||(w[22]=n("button",{title:"Copy Code",class:"copy"},null,-1)),w[23]||(w[23]=n("span",{class:"lang"},"sh",-1)),n("pre",m,[n("code",null,[n("span",_,[w[16]||(w[16]=n("span",{style:{color:"#94EEFF"}},"Evolve",-1)),w[17]||(w[17]=n("span",{style:{color:"#BFF3C2"}}," Version:",-1)),n("span",A," "+t(l(a).celestiaNodeMainnetEvolveTag),1)]),w[21]||(w[21]=i("\n",-1)),n("span",k,[w[18]||(w[18]=n("span",{style:{color:"#94EEFF"}},"Celestia",-1)),w[19]||(w[19]=n("span",{style:{color:"#BFF3C2"}}," Node",-1)),w[20]||(w[20]=n("span",{style:{color:"#BFF3C2"}}," Version:",-1)),n("span",T," "+t(l(a).celestiaNodeMainnetTag),1)])])])])])]),w[26]||(w[26]=o('<ul><li><a href="https://docs.celestia.org/how-to-guides/arabica-devnet" target="_blank" rel="noreferrer">Arabica Devnet</a></li><li><a href="https://docs.celestia.org/how-to-guides/mocha-testnet" target="_blank" rel="noreferrer">Mocha Testnet</a></li><li><a href="https://docs.celestia.org/how-to-guides/mainnet" target="_blank" rel="noreferrer">Mainnet Beta</a></li></ul><p>The main difference lies in how you fund your wallet address: using testnet TIA or <a href="https://docs.celestia.org/learn/tia#overview-of-tia" target="_blank" rel="noreferrer">TIA</a> for Mainnet Beta.</p><p>After successfully starting a light node, it&#39;s time to start posting the batches of blocks of data that your chain generates to Celestia.</p><h2 id="prerequisites" tabindex="-1">🏗️ Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;🏗️ Prerequisites {#prerequisites}&quot;">​</a></h2><ul><li><code>gmd</code> CLI installed from the <a href="./../gm-world">gm-world</a> tutorial.</li></ul><h2 id="🛠️-configuring-flags-for-da" tabindex="-1">🛠️ Configuring flags for DA <a class="header-anchor" href="#🛠️-configuring-flags-for-da" aria-label="Permalink to &quot;🛠️ Configuring flags for DA&quot;">​</a></h2><p>Now that we are posting to the Celestia DA instead of the local DA, the <code>evolve start</code> command requires three DA configuration flags:</p><ul><li><code>--evnode.da.start_height</code></li><li><code>--evnode.da.auth_token</code></li><li><code>--evnode.da.namespace</code></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Optionally, you could also set the <code>--evnode.da.block_time</code> flag. This should be set to the finality time of the DA layer, not its actual block time, as Evolve does not handle reorganization logic. The default value is 15 seconds.</p></div><p>Let&#39;s determine which values to provide for each of them.</p><p>First, let&#39;s query the DA layer start height using our light node.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">DA_BLOCK_HEIGHT</span><span style="color:#767676;">=$(</span><span style="color:#94EEFF;">celestia</span><span style="color:#BFF3C2;"> header</span><span style="color:#BFF3C2;"> network-head</span><span style="color:#888888;"> |</span><span style="color:#94EEFF;"> jq</span><span style="color:#FFECB6;"> -r</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">.result.header.height</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#767676;">)</span></span>\n<span class="line"><span style="color:#94EEFF;">echo</span><span style="color:#FFECB6;"> -e</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">\\n Your DA_BLOCK_HEIGHT is $DA_BLOCK_HEIGHT \\n</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p>The output of the command above will look similar to this:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;"> Your</span><span style="color:#BFF3C2;"> DA_BLOCK_HEIGHT</span><span style="color:#BFF3C2;"> is</span><span style="color:#FFECB6;"> 2127672</span></span></code></pre></div><p>Now, let&#39;s obtain the authentication token of your light node using the following command:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-Tgz_x" id="tab-1Wf27hU" checked><label data-title="Arabica Devnet" for="tab-1Wf27hU">Arabica Devnet</label><input type="radio" name="group-Tgz_x" id="tab-kq6KGh4"><label data-title="Mocha Testnet" for="tab-kq6KGh4">Mocha Testnet</label><input type="radio" name="group-Tgz_x" id="tab-6K3FWCp"><label data-title="Mainnet Beta" for="tab-6K3FWCp">Mainnet Beta</label></div><div class="blocks"><div class="language-bash active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">AUTH_TOKEN</span><span style="color:#767676;">=$(</span><span style="color:#94EEFF;">celestia</span><span style="color:#BFF3C2;"> light</span><span style="color:#BFF3C2;"> auth</span><span style="color:#BFF3C2;"> write</span><span style="color:#FFECB6;"> --p2p.network</span><span style="color:#BFF3C2;"> arabica</span><span style="color:#767676;">)</span></span>\n<span class="line"><span style="color:#94EEFF;">echo</span><span style="color:#FFECB6;"> -e</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">\\n Your DA AUTH_TOKEN is $AUTH_TOKEN \\n</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">AUTH_TOKEN</span><span style="color:#767676;">=$(</span><span style="color:#94EEFF;">celestia</span><span style="color:#BFF3C2;"> light</span><span style="color:#BFF3C2;"> auth</span><span style="color:#BFF3C2;"> write</span><span style="color:#FFECB6;"> --p2p.network</span><span style="color:#BFF3C2;"> mocha</span><span style="color:#767676;">)</span></span>\n<span class="line"><span style="color:#94EEFF;">echo</span><span style="color:#FFECB6;"> -e</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">\\n Your DA AUTH_TOKEN is $AUTH_TOKEN \\n</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">AUTH_TOKEN</span><span style="color:#767676;">=$(</span><span style="color:#94EEFF;">celestia</span><span style="color:#BFF3C2;"> light</span><span style="color:#BFF3C2;"> auth</span><span style="color:#BFF3C2;"> write</span><span style="color:#767676;">)</span></span>\n<span class="line"><span style="color:#94EEFF;">echo</span><span style="color:#FFECB6;"> -e</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">\\n Your DA AUTH_TOKEN is $AUTH_TOKEN \\n</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div></div></div><p>The output of the command above will look similar to this:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;"> Your</span><span style="color:#BFF3C2;"> DA</span><span style="color:#BFF3C2;"> AUTH_TOKEN</span><span style="color:#BFF3C2;"> is</span><span style="color:#BFF3C2;"> eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJBbGxvdyI6WyJwdWJsaWMiLCJyZWFkIiwid3JpdGUiXX0.cSrJjpfUdTNFtzGho69V0D_8kyECn9Mzv8ghJSpKRDE</span></span></code></pre></div><p>Next, let&#39;s set up the namespace to be used for posting data on Celestia. Evolve supports separate namespaces for headers and data, but for simplicity, we&#39;ll use a single namespace for both:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">DA_NAMESPACE</span><span style="color:#767676;">=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">fancy_namespace</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p><strong>Advanced Configuration:</strong> For production deployments, you can use separate namespaces for headers and data to optimize syncing:</p><ul><li><code>--evnode.da.header_namespace</code> for block headers</li><li><code>--evnode.da.data_namespace</code> for transaction data</li></ul><p>The namespace values are automatically encoded by the node to ensure compatibility with Celestia.</p><p><a href="https://docs.celestia.org/tutorials/node-tutorial#namespaces" target="_blank" rel="noreferrer">Learn more about namespaces</a>. :::</p><p>Lastly, set your DA address for your light node, which by default runs at port 26658:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">DA_ADDRESS</span><span style="color:#767676;">=</span><span style="color:#BFF3C2;">http://localhost:26658</span></span></code></pre></div><h2 id="🔥-running-your-chain-connected-to-celestia-light-node" tabindex="-1">🔥 Running your chain connected to Celestia light node <a class="header-anchor" href="#🔥-running-your-chain-connected-to-celestia-light-node" aria-label="Permalink to &quot;🔥 Running your chain connected to Celestia light node&quot;">​</a></h2><p>Finally, let&#39;s initiate the chain node with all the flags:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">gmd</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.node.aggregator</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.auth_token</span><span style="color:#DBD7CA;"> $AUTH_TOKEN </span><span style="color:#FFECB6;">\\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.header_namespace</span><span style="color:#DBD7CA;"> $DA_NAMESPACE </span><span style="color:#FFECB6;">\\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.data_namespace</span><span style="color:#DBD7CA;"> $DA_NAMESPACE </span><span style="color:#FFECB6;">\\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.address</span><span style="color:#DBD7CA;"> $DA_ADDRESS</span></span></code></pre></div><p>Now, the chain is running and posting blocks (aggregated in batches) to Celestia. You can view your chain by using your namespace or account on one of Celestia&#39;s block explorers.</p><p>For example, <a href="https://arabica.celenium.io/" target="_blank" rel="noreferrer">here on Celenium for Arabica</a>.</p><p>Other explorers:</p><ul><li><a href="https://docs.celestia.org/how-to-guides/arabica-devnet" target="_blank" rel="noreferrer">Arabica testnet</a></li><li><a href="https://docs.celestia.org/how-to-guides/mocha-testnet" target="_blank" rel="noreferrer">Mocha testnet</a></li><li><a href="https://docs.celestia.org/how-to-guides/mainnet" target="_blank" rel="noreferrer">Mainnet Beta</a></li></ul><h2 id="🎉-next-steps" tabindex="-1">🎉 Next steps <a class="header-anchor" href="#🎉-next-steps" aria-label="Permalink to &quot;🎉 Next steps&quot;">​</a></h2><p>Congratulations! You&#39;ve built a local chain that posts data to Celestia&#39;s DA layer. Well done! Now, go forth and build something great! Good luck!</p>',35))]))});export{D as __pageData,N as default};
